@import url('https://fonts.googleapis.com/css2?family=Press+Start+2P&family=Roboto+Mono:wght@400;700&display=swap');

:root {
    --dark-bg: #0a0a1a;
    --neon-blue: #00e5ff; /* Cyan-like neon */
    --neon-magenta: #ff00cc; /* Magenta neon */
    --neon-green: #00ff99; /* Green neon for success/active states */
    --neon-red: #ff3366; /* Red for errors/warnings */
    --light-grey: #cccccc;
    --dark-grey-text: #888888;

    --font-primary: 'Press Start 2P', cursive; /* For main titles */
    --font-secondary: 'Roboto Mono', monospace; /* For body text, inputs */
}

/* Base Styles */
body {
    font-family: var(--font-secondary);
    background-color: var(--dark-bg);
    color: var(--light-grey);
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    margin: 0;
    overflow: hidden; /* Prevent scrollbar from glitch effects */
    letter-spacing: 0.05em; /* Subtle spacing for monospace */
    line-height: 1.6;
    font-size: 16px;
}

/* Main Login Container */
.login-container {
    background-color: rgba(10, 10, 26, 0.7); /* Slightly lighter than body, semi-transparent */
    border: 2px solid var(--neon-blue);
    box-shadow: 0 0 15px var(--neon-blue), 0 0 30px var(--neon-magenta) inset;
    padding: 40px;
    border-radius: 10px;
    text-align: center;
    max-width: 450px;
    width: 90%;
    position: relative;
    animation: container-glow 1.8s infinite alternate ease-in-out;
    box-sizing: border-box; /* Include padding in width calculation */
}

@keyframes container-glow {
    from {
        box-shadow: 0 0 15px var(--neon-blue), 0 0 30px var(--neon-magenta) inset;
    }
    to {
        box-shadow: 0 0 25px var(--neon-blue), 0 0 50px var(--neon-magenta) inset;
    }
}

/* Glitch Title */
.glitch {
    font-family: var(--font-primary);
    font-size: 2.5em;
    color: var(--neon-blue);
    text-shadow: 0 0 10px var(--neon-blue), 0 0 20px var(--neon-blue), 0 0 40px var(--neon-blue);
    position: relative;
    margin-bottom: 20px;
    line-height: 1;
    text-transform: uppercase;
    user-select: none; /* Prevent selection that breaks glitch effect */
}

.glitch::before,
.glitch::after {
    content: attr(data-text);
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: var(--dark-bg);
    overflow: hidden;
}

.glitch::before {
    left: 2px;
    text-shadow: -2px 0 var(--neon-magenta);
    animation: glitch-anim-1 2s infinite linear alternate-reverse;
}

.glitch::after {
    left: -2px;
    text-shadow: -2px 0 var(--neon-green);
    animation: glitch-anim-2 2s infinite linear alternate-reverse;
}

/* Glitch Keyframes - Random clipping effects */
@keyframes glitch-anim-1 {
    0% { clip-path: inset(80% -6px 0 0); }
    15% { clip-path: inset(70% -6px 0 0); }
    30% { clip-path: inset(50% -6px 0 0); }
    45% { clip-path: inset(20% -6px 0 0); }
    60% { clip-path: inset(40% -6px 0 0); }
    75% { clip-path: inset(10% -6px 0 0); }
    90% { clip-path: inset(90% -6px 0 0); }
    100% { clip-path: inset(80% -6px 0 0); }
}

@keyframes glitch-anim-2 {
    0% { clip-path: inset(20% -6px 0 0); }
    10% { clip-path: inset(5% -6px 0 0); }
    20% { clip-path: inset(75% -6px 0 0); }
    30% { clip-path: inset(30% -6px 0 0); }
    40% { clip-path: inset(90% -6px 0 0); }
    50% { clip-path: inset(40% -6px 0 0); }
    60% { clip-path: inset(10% -6px 0 0); }
    70% { clip-path: inset(60% -6px 0 0); }
    80% { clip-path: inset(35% -6px 0 0); }
    90% { clip-path: inset(85% -6px 0 0); }
    100% { clip-path: inset(20% -6px 0 0); }
}

/* Sub Title */
.sub-title {
    font-family: var(--font-secondary);
    color: var(--neon-magenta);
    text-shadow: 0 0 5px var(--neon-magenta);
    margin-bottom: 30px;
    font-size: 1em;
    text-transform: uppercase;
}

/* Error Message */
.error-message {
    color: var(--neon-red);
    text-shadow: 0 0 8px var(--neon-red), 0 0 15px rgba(255, 51, 102, 0.5); /* More prominent glow */
    margin-bottom: 20px;
    font-weight: bold;
    padding: 10px;
    border: 1px solid var(--neon-red);
    border-radius: 5px;
    background-color: rgba(255, 51, 102, 0.1);
}

/* Form Styles */
.login-form {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.input-group {
    text-align: left;
}

.input-label {
    display: block;
    color: var(--neon-blue);
    margin-bottom: 8px;
    font-size: 0.9em;
    text-shadow: 0 0 3px var(--neon-blue), 0 0 8px rgba(0, 229, 255, 0.5); /* Subtle extra glow */
    text-transform: uppercase;
}

input[type="text"],
input[type="password"] {
    width: 100%;
    padding: 12px 15px;
    background-color: rgba(0, 0, 0, 0.5); /* Semi-transparent dark */
    border: 1px solid var(--neon-magenta);
    border-radius: 5px;
    color: var(--neon-green); /* Input text color */
    font-family: var(--font-secondary);
    font-size: 1em;
    outline: none;
    box-shadow: 0 0 5px var(--neon-magenta);
    transition: all 0.3s ease;
    box-sizing: border-box; /* Include padding in width calculation */
}

input[type="text"]:focus,
input[type="password"]:focus {
    border-color: var(--neon-blue);
    box-shadow: 0 0 8px var(--neon-blue), 0 0 15px var(--neon-blue) inset;
    background-color: rgba(0, 0, 0, 0.7);
    color: var(--neon-green);
}

input::placeholder {
    color: var(--dark-grey-text);
    opacity: 0.7;
}

/* Button Styles */
.login-button {
    background-color: var(--neon-blue);
    color: var(--dark-bg); /* Dark text on bright button */
    border: 2px solid var(--neon-blue);
    padding: 15px 25px;
    font-family: var(--font-primary);
    font-size: 1.1em;
    text-transform: uppercase;
    cursor: pointer;
    border-radius: 5px;
    box-shadow: 0 0 10px var(--neon-blue), 0 0 20px rgba(0, 229, 255, 0.5); /* Enhanced glow */
    transition: all 0.3s ease;
    letter-spacing: 0.1em;
    margin-top: 10px;
    font-weight: bold;
    outline: none;
}

.login-button:hover {
    background-color: transparent;
    color: var(--neon-blue);
    box-shadow: 0 0 20px var(--neon-blue), 0 0 30px var(--neon-magenta);
    transform: translateY(-2px);
}

.login-button:active {
    transform: translateY(0);
    box-shadow: 0 0 5px var(--neon-blue);
    background-color: var(--neon-blue);
    color: var(--dark-bg);
}

/* Footer Text */
.footer-text {
    margin-top: 30px;
    color: var(--dark-grey-text);
    font-size: 0.8em;
    text-shadow: 0 0 2px var(--dark-grey-text);
    font-family: var(--font-secondary);
}
